const items = $input.all();

function standardizePhone(raw) {
  if (!raw || typeof raw !== 'string') return { cleaned: '', original: raw || '' };
  const digits = raw.replace(/\D/g, '');
  if (digits.length === 0) return { cleaned: '', original: raw };
  if (digits.length === 10) {
    return { cleaned: `+1-${digits.slice(0,3)}-${digits.slice(3,6)}-${digits.slice(6)}`, original: raw };
  }
  if (digits.length === 11 && digits[0] === '1') {
    return { cleaned: `+1-${digits.slice(1,4)}-${digits.slice(4,7)}-${digits.slice(7)}`, original: raw };
  }
  return { cleaned: `+${digits}`, original: raw };
}

function parseCSV(csvText) {
  const lines = csvText.trim().split(/\r?\n/);
  if (lines.length < 2) return [];
  // Normalize headers to lowercase to ensure consistent key access
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, '').toLowerCase());
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    const values = [];
    let current = '';
    let inQuotes = false;
    for (let c = 0; c < line.length; c++) {
      const ch = line[c];
      if (ch === '"') {
        if (inQuotes && line[c + 1] === '"') {
          // RFC 4180: escaped quote inside quoted field
          current += '"';
          c++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (ch === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += ch;
      }
    }
    values.push(current.trim());
    const row = {};
    headers.forEach((h, idx) => {
      row[h] = (values[idx] || '').trim();
    });
    rows.push(row);
  }
  return rows;
}

const PHONE_KEYS = new Set(['phone', 'phone_number', 'phonenumber', 'mobile']);

const results = [];

for (const item of items) {
  let csvText = '';

  // Primary: use normalized raw_body from Set node (string only)
  if (item.json.raw_body && typeof item.json.raw_body === 'string' && item.json.raw_body.trim().length > 0) {
    csvText = item.json.raw_body;
  } else if (item.binary) {
    // Fallback: binary body (e.g. direct file upload)
    const binaryKey = Object.keys(item.binary)[0];
    if (binaryKey) {
      const buf = Buffer.from(item.binary[binaryKey].data, 'base64');
      csvText = buf.toString('utf-8');
    }
  }

  if (!csvText || csvText.trim().length === 0) {
    results.push({
      json: {
        success: false,
        error: 'Request body is empty or missing. Please provide a valid CSV payload.',
        cleaned_rows: [],
        invalid_phone_rows: [],
        total_input_rows: 0,
        total_output_rows: 0,
        rows_removed: 0
      }
    });
    continue;
  }

  const parsedRows = parseCSV(csvText);

  if (parsedRows.length === 0) {
    results.push({
      json: {
        success: false,
        error: 'CSV contained no data rows. Ensure the file has a header row and at least one data row.',
        cleaned_rows: [],
        invalid_phone_rows: [],
        total_input_rows: 0,
        total_output_rows: 0,
        rows_removed: 0
      }
    });
    continue;
  }

  // All header keys are already lowercase from parseCSV
  const filteredRows = parsedRows.filter(row => {
    const name = (row['name'] || '').trim();
    const email = (row['email'] || '').trim();
    return name.length > 0 && email.length > 0;
  });

  const invalidPhoneRows = [];
  const cleanedRows = filteredRows.map(row => {
    const cleaned = {};
    for (const key of Object.keys(row)) {
      const val = (row[key] || '').trim();
      if (PHONE_KEYS.has(key)) {
        const phoneResult = standardizePhone(val);
        cleaned[key] = phoneResult.cleaned;
      } else {
        cleaned[key] = val;
      }
    }
    // Collect invalid phone rows AFTER the full cleaned row is assembled
    for (const key of Object.keys(cleaned)) {
      if (PHONE_KEYS.has(key)) {
        const originalVal = (row[key] || '').trim();
        const digits = originalVal.replace(/\D/g, '');
        if (originalVal.length > 0 && digits.length !== 10 && !(digits.length === 11 && digits[0] === '1')) {
          invalidPhoneRows.push({ row: Object.assign({}, cleaned), original_phone: originalVal });
        }
      }
    }
    return cleaned;
  });

  results.push({
    json: {
      success: true,
      error: null,
      cleaned_rows: cleanedRows,
      invalid_phone_rows: invalidPhoneRows,
      total_input_rows: parsedRows.length,
      total_output_rows: cleanedRows.length,
      rows_removed: parsedRows.length - cleanedRows.length
    }
  });
}

return results;
